// Weighted random pick: 40% renter, 40% owner, 20% service.
// Tweak weights here to change monthly distribution.

const weights = { renter: 0.4, owner: 0.4, service: 0.2 };
const r = Math.random();

let perspective;
if (r < weights.renter) {
  perspective = 'renter';
} else if (r < weights.renter + weights.owner) {
  perspective = 'owner';
} else {
  perspective = 'service';
}

return [{ json: { perspective } }];

