// Deterministic post-processing: runs brand-voice checks and either
// passes the post through or prepares a regen request body with audit feedback.
//
// Outputs:
//   { choices, _validate: { passed, issues, regenRequestBody | null } }
//
// The IF node downstream branches on _validate.passed.

const content = $input.first().json.choices[0].message.content;
const requestBody = $('Build prompts').first().json.requestBody;
const perspective = $('Build prompts').first().json.perspective;

const issues = [];

// 1. Brand name must appear
if (!content.includes('Lorent Bloom')) {
  issues.push('Brand name "Lorent Bloom" missing from the post — it must appear in the body, exactly as "Lorent Bloom" (not transliterated).');
}

// 2. Lowercase "вы" detection (formal address must be capital Вы)
const lowerVyPattern = /(^|[\s,.;:!?\-—«"])вы(\s|[,.;:!?\-—»"])/;
if (lowerVyPattern.test(content)) {
  issues.push('Lowercase "вы" detected — formal address must always be capitalized "Вы" (capital В then lowercase ы).');
}

// 3. ALL-CAPS "ВЫ" detection (also wrong)
if (/(^|[\s,.;:!?\-—«"])ВЫ(\s|[,.;:!?\-—»"])/.test(content)) {
  issues.push('ALL-CAPS "ВЫ" detected — should be "Вы" (capital В then lowercase ы).');
}

// 4. Informal "ты" detection (Russian forbids "ты" in this brand)
if (/(^|[\s,.;:!?\-—«"])ты(\s|[,.;:!?\-—»"])/i.test(content)) {
  issues.push('Informal "ты" detected — brand voice requires formal "Вы" throughout, never "ты".');
}

// 5. Forbidden generic-AI phrases
const forbidden = [
  { rx: /С помощью нашей платформы/i, name: '"С помощью нашей платформы" (use "В Lorent Bloom" instead)' },
  { rx: /часто возникает необходимость/i, name: '"часто возникает необходимость" (open with a concrete fact instead)' },
  { rx: /многие сталкиваются с/i, name: '"многие сталкиваются с"' },
  { rx: /Это разумное решение для тех/i, name: '"Это разумное решение для тех..."' },
  { rx: /Это поможет (Вам|вам) сэкономить/i, name: '"Это поможет Вам сэкономить"' },
  { rx: /(^|\s)успейте/i, name: '"успейте" (no urgency cliches)' },
  { rx: /не упустите/i, name: '"не упустите"' },
  { rx: /ограниченное предложение/i, name: '"ограниченное предложение"' },
  { rx: /тысячи (пользователей|людей)/i, name: '"тысячи пользователей/людей" (no fabricated stats)' },
  { rx: /самый безопасный/i, name: '"самый безопасный" (no unprovable superlatives)' },
  { rx: /лучший в Молдове/i, name: '"лучший в Молдове" (no unprovable superlatives)' },
  { rx: /наша платформа/i, name: '"наша платформа" (use "Lorent Bloom" instead)' },
  { rx: /многие пользователи/i, name: '"многие пользователи" — implied user count without basis' },
  { rx: /около \d+\s*лей в день/i, name: '"около X лей в день" — vague price, use a specific number tied to a real item' },
  { rx: /безделушк[аи]/i, name: '"безделушки" — dismissive of real items; use "вещи" or specific item names' }
];
for (const { rx, name } of forbidden) {
  if (rx.test(content)) issues.push(`Forbidden phrase: ${name}`);
}

// 6. Length (80-150 target; tolerate 60-200)
const wordCount = content.trim().split(/\s+/).filter(w => w.length > 0).length;
if (wordCount < 60) issues.push(`Too short: ${wordCount} words (target 80-150, minimum 60).`);
if (wordCount > 200) issues.push(`Too long: ${wordCount} words (target 80-150, max 200).`);

// 7. Mixed scripts (Russian post should not contain Latin city names mid-text)
const latinCities = ['Chișinău', 'Bălți', 'Cahul', 'Tiraspol', 'Comrat'];
for (const lc of latinCities) {
  if (content.includes(lc)) {
    issues.push(`Mixed script: "${lc}" (Latin) in a Russian post — use Cyrillic equivalent.`);
  }
}

// 8. Emoji detection
const emojiPattern = /[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{1F000}-\u{1F02F}\u{1F0A0}-\u{1F0FF}\u{1F100}-\u{1F1FF}\u{1F200}-\u{1F2FF}\u{2700}-\u{27BF}\u{2B50}\u{2B55}\u{2705}\u{274C}]/u;
if (emojiPattern.test(content)) {
  issues.push('Emoji detected — brand voice forbids ALL emojis (decorative or functional). Use plain text.');
}

// 9. CJK / foreign script characters (Llama token leak — '找到', '挂', etc.)
const cjkPattern = /[\u4E00-\u9FFF\u3040-\u30FF]/;
if (cjkPattern.test(content)) {
  issues.push('Foreign script characters (Chinese/Japanese) detected — Llama token leak. Regenerate with feedback to use only Cyrillic.');
}

const passed = issues.length === 0;
let regenRequestBody = null;

if (!passed) {
  const fixInstruction = `The draft you just wrote has these brand-voice issues:

${issues.map((iss, i) => `${i + 1}. ${iss}`).join('\n')}

Rewrite the post fixing EVERY issue. Keep the same topic, perspective (${perspective}), and approximate length. Output ONLY the corrected post — no commentary, no labels, no "Here is the corrected post:".`;

  regenRequestBody = {
    ...requestBody,
    messages: [
      ...requestBody.messages,
      { role: 'assistant', content },
      { role: 'user', content: fixInstruction }
    ]
  };
}

return [{
  json: {
    choices: $input.first().json.choices,
    _validate: {
      passed,
      issues,
      wordCount,
      regenRequestBody
    }
  }
}];

// 1. Convert Cloudflare's base64 image response into n8n binary data.
