//   PERSPECTIVE TAG: renter → #АрендуйВМолдове, owner → #СдайВАренду, service → (none)
//   TOPIC TAGS: 2 picked at random from the topic's curated pool

const base64 = $input.first().json.result.image;

if (!base64) {
  throw new Error('Cloudflare AI returned no image. Full response: ' + JSON.stringify($input.first().json));
}

// Final text from whichever Groq branch produced it (original or regenerated).
const text = $('Merge text branches').first().json.choices[0].message.content;
const perspective = $('Build prompts').first().json.perspective;
const topic = $('Build prompts').first().json.selectedTopic;

// ── Build hashtags ──
const hashtags = ['#LorentBloom', '#АрендаМолдова'];

// Perspective-specific tag (action-oriented)
if (perspective === 'renter') {
  hashtags.push('#АрендуйВМолдове');
} else if (perspective === 'owner') {
  hashtags.push('#СдайВАренду');
}
// service: no perspective tag — covered by #LorentBloom + #АрендаМолдова

// Pick 2 random topic-specific hashtags from the curated pool
const topicTags = topic.hashtags || [];
const shuffled = [...topicTags].sort(() => Math.random() - 0.5);
const randomPicks = shuffled.slice(0, Math.min(2, shuffled.length));
hashtags.push(...randomPicks);

